import{_ as e,c as a,o,a4 as t}from"./chunks/framework.nQaBHiNx.js";const u=JSON.parse('{"title":"编写可读代码的艺术","description":"","frontmatter":{},"headers":[],"relativePath":"computer/book/the-art-of-readable-code/index.md","filePath":"computer/book/the-art-of-readable-code/index.md"}'),r={name:"computer/book/the-art-of-readable-code/index.md"},c=t('<h1 id="编写可读代码的艺术" tabindex="-1">编写可读代码的艺术 <a class="header-anchor" href="#编写可读代码的艺术" aria-label="Permalink to &quot;编写可读代码的艺术&quot;">​</a></h1><p>细节决定成败，思路清晰、言简意赅的代码让程序员一目了然；而格式凌乱、拖沓冗长的代码让程序员一头雾水。除了可以正确运行以外，优秀的代码必须具备良好的可读性，编写的代码要使其他人能在最短的时间内理解才行。本书旨在强调代码对人的友好性和可读性。</p><p>本书关注编码的细节，总结了很多提高代码可读性的小技巧，看似都微不足道，但是对于整个软件系统的开发而言，它们与宏观的架构决策、设计思想、指导原则同样重要。编码不仅仅只是一种技术，也是一门艺术，编写可读性高的代码尤其如此。如果你要成为一位优秀的程序员，要想开发出高质量的软件系统，必须从细处着手，做到内外兼修，本书将为你提供有效的指导。</p><h2 id="作者简介" tabindex="-1">作者简介 <a class="header-anchor" href="#作者简介" aria-label="Permalink to &quot;作者简介&quot;">​</a></h2><p>Dustin Boswell 毕业于加州理工大学，资深软件工程师，在Google就职多年，负责Web爬虫和程序设计相关的工作。他专注于前端、后端，服务器架构、机器学习、大数据、系统和网站等技术领域的研究和实践，经验十分丰富。他现在是MyLikes的软件工程师。</p><p>Trevor Foucher 资深软件工程师和技术经理，先后在Microsoft和Google工作了数十年，在Microsoft担任软件工程师、技术经理以及安全产品技术主管，在Google从事广告应用开发和搜索基础结构研发相关的工作。</p><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><p><a href="https://book.douban.com/subject/10797189/" target="_blank" rel="noreferrer">豆瓣读书 - 《编写可读代码的艺术》</a></p>',8),n=[c];function s(d,i,l,_,h,p){return o(),a("div",null,n)}const b=e(r,[["render",s]]);export{u as __pageData,b as default};
